#define DEFAULT_ORDER 256

typedef struct {
    int value;
} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;


__kernel void
findK(
    long height,
    __global knode *knodesD,
    long knodes_elem,
    __global record *recordsD,

    __global long *currKnodeD,
    __global long *offsetD,
    __global int *keysD,
    __global record *ansD)
{
    int thid = get_local_id(0);
    int bid = get_group_id(0);

    // For each level of the tree height
    for (int i = 0; i < height; i++) {
        // Load current knode index for this block
        long curr_node_idx = currKnodeD[bid];
        knode curr_node = knodesD[curr_node_idx];

        // Check keys thid and thid+1 for key range
        if (curr_node.keys[thid] <= keysD[bid] && curr_node.keys[thid + 1] > keysD[bid]) {
            if (curr_node.indices[thid] < knodes_elem) {
                offsetD[bid] = curr_node.indices[thid];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    long curr_node_idx = currKnodeD[bid];
    knode curr_node = knodesD[curr_node_idx];

    if (curr_node.keys[thid] == keysD[bid]) {
        ansD[bid].value = recordsD[curr_node.indices[thid]].value;
    }
}

