    int keys[DEFAULT_ORDER_2 + 1];
    int is_leaf;
    int num_keys;
} knode;


__kernel void
findRangeK(
    long height,

    __global knode *knodesD,
    long knodes_elem,

    __global long *currKnodeD,
    __global long *offsetD,
    __global long *lastKnodeD,
    __global long *offset_2D,
    __global int *startD,
    __global int *endD,
    __global int *RecstartD,
    __global int *ReclenD)
{
    int thid = get_local_id(0);
    int bid = get_group_id(0);

    for (int i = 0; i < height; i++) {
        long curr_node_idx = currKnodeD[bid];
        knode curr_node = knodesD[curr_node_idx];

        if (curr_node.keys[thid] <= startD[bid] && curr_node.keys[thid + 1] > startD[bid]) {
            if (curr_node.indices[thid] < knodes_elem) {
                offsetD[bid] = curr_node.indices[thid];
            }
        }

        long last_node_idx = lastKnodeD[bid];
        knode last_node = knodesD[last_node_idx];

        if (last_node.keys[thid] <= endD[bid] && last_node.keys[thid + 1] > endD[bid]) {
            if (last_node.indices[thid] < knodes_elem) {
                offset_2D[bid] = last_node.indices[thid];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
            lastKnodeD[bid] = offset_2D[bid];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    long curr_node_idx = currKnodeD[bid];
    knode curr_node = knodesD[curr_node_idx];

    if (curr_node.keys[thid] == startD[bid]) {
        RecstartD[bid] = curr_node.indices[thid];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    long last_node_idx = lastKnodeD[bid];
    knode last_node = knodesD[last_node_idx];

    if (last_node.keys[thid] == endD[bid]) {
        ReclenD[bid] = last_node.indices[thid] - RecstartD[bid] + 1;
    }
}
